	// Mark this variable false if the hooked plugin doesn't suggest sequential plugins to continue processing.
	$continue_process = true;

	$my_mail_parameters = array(
		'to' => &$to,
		'subject' => &$subject,
		'message' => &$message,
		'from' => &$from,
		'charset' => &$charset,
